'use client'

import * as React from 'react'

const buttonStyle = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  minHeight: '40px',
  padding: '0 16px',
  backgroundColor: '#16a34a',
  border: '0',
  borderRadius: '6px',
  boxShadow: '0 1px 2px rgba(15, 23, 42, 0.16)',
  color: 'white',
  cursor: 'pointer',
  fontFamily:
    '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
  fontSize: '13px',
  fontWeight: 700,
}

export function NodeModuleClientWidget(props) {
  const [count, setCount] = React.useState(0)

  return React.createElement(
    'button',
    {
      type: 'button',
      'data-testid': 'node-module-client-widget',
      style: buttonStyle,
      onClick: () => setCount((value) => value + 1),
    },
    `${props.label}: ${count}`,
  )
}
